import { h, Signal } from '@tu-lang/runtime'

export const frontmatter = new Signal.State({})
export const Page = () => h("div", {}, [h("$static", {}, [], "<article class=\"tu-markdown\"><h1>Install</h1>\n<p>Tu is published to npm under the <code>@tu-lang/*</code> scope (and <code>create-tu</code> for the project starter). It is currently <strong>pre-alpha</strong> — the <code>latest</code> tag is not used; releases land on the <code>alpha</code> tag.</p>\n<h2>Use Tu in a project</h2>\n<h3>Compiler + runtime + Vite plugin</h3>\n<pre><code class=\"language-sh\">pnpm add -D @tu-lang/vite@alpha @tu-lang/compiler@alpha\npnpm add @tu-lang/runtime@alpha\n</code></pre>\n<pre><code class=\"language-ts\">// vite.config.ts\nimport { defineConfig } from 'vite'\nimport tu from '@tu-lang/vite'\n\nexport default defineConfig({\n  plugins: [tu()],\n})\n</code></pre>\n<p>Now any <code>*.tu</code> file in your project gets compiled on import.</p>\n<h3>Scaffold a fresh project</h3>\n<pre><code class=\"language-sh\">pnpm create tu my-app\ncd my-app\npnpm dev\n</code></pre>\n<p>(<code>create-tu</code> is the npm starter template; the v0.1 version is minimal — expect rough edges.)</p>\n<h3>Type-check <code>.tu</code> files in CI</h3>\n<pre><code class=\"language-sh\">pnpm add -D @tu-lang/cli@alpha\npnpx tu check src/**/*.tu\n</code></pre>\n<h2>VS Code: syntax + LSP</h2>\n<p>The VS Code extension (<code>vscode-tu</code>) is <strong>not yet on the Marketplace</strong>. Two ways to use it today:</p>\n<h3>Option A — install from a <code>.vsix</code></h3>\n<p>Download the latest <code>.vsix</code> from this site and install it manually:</p>\n<ul>\n<li><a href=\"./install/vscode-tu-latest.vsix\">vscode-tu-latest.vsix</a> <em>(coming soon — built by the docs deploy workflow)</em></li>\n</ul>\n<pre><code class=\"language-sh\">code --install-extension vscode-tu-latest.vsix\n</code></pre>\n<h3>Option B — clone + dev-install</h3>\n<pre><code class=\"language-sh\">git clone https://github.com/mowtwo/tu\ncd tu\npnpm install\npnpm --filter vscode-tu dev:install\n</code></pre>\n<p>Then in VS Code: <code>Cmd+Shift+P</code> → “Developer: Reload Window”. Tu syntax highlighting, diagnostics squiggles, hover, completion, goto-definition, and rename all light up.</p>\n<h2>TextMate grammar (for other editors / tooling)</h2>\n<p>The same grammar that drives the VS Code extension and the syntax highlighting on this site:</p>\n<ul>\n<li><a href=\"./grammar/tu.tmLanguage.json\">tu.tmLanguage.json</a></li>\n</ul>\n<p>Drop it into any TextMate-compatible editor (Sublime, Atom, Nova, …) or feed it to Shiki / highlight.js / a custom highlighter.</p>\n<h2>AI agent skill</h2>\n<p>If you’re an LLM (or driving one), the <a href=\"./skill\">skill page</a> is written for direct ingestion — copy the markdown into a system prompt, save it as <code>.claude/skills/tu/SKILL.md</code>, or fetch the plain-text mirror at <a href=\"./llms.txt\"><code>/llms.txt</code></a>.</p>\n<h2>What’s published</h2>\n<table>\n<thead>\n<tr>\n<th>Package</th>\n<th>Role</th>\n<th>Stage</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/runtime\"><code>@tu-lang/runtime</code></a></td>\n<td>Signal cells + DOM glue (<code>h</code>, <code>mount</code>, <code>hydrate</code>, <code>renderToString</code>, <code>Fragment</code>, <code>defineCustomElement</code>)</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/compiler\"><code>@tu-lang/compiler</code></a></td>\n<td>Lexer / parser / codegen / source maps</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/vite\"><code>@tu-lang/vite</code></a></td>\n<td>Vite plugin — load <code>.tu</code> modules on import</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/lsp\"><code>@tu-lang/lsp</code></a></td>\n<td>Language server (diagnostics + hover + completion + def + rename)</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/cli\"><code>@tu-lang/cli</code></a></td>\n<td><code>tu build</code> / <code>tu dev</code> / <code>tu check</code> / <code>tu fmt</code></td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/format\"><code>@tu-lang/format</code></a></td>\n<td>Prettier plugin (dprint port later)</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/@tu-lang/std\"><code>@tu-lang/std</code></a></td>\n<td>Standard library — placeholder</td>\n<td>alpha</td>\n</tr>\n<tr>\n<td><a href=\"https://www.npmjs.com/package/create-tu\"><code>create-tu</code></a></td>\n<td><code>npm create tu</code> scaffold</td>\n<td>alpha</td>\n</tr>\n</tbody>\n</table>\n<p>Source for everything: <a href=\"https://github.com/mowtwo/tu\">github.com/mowtwo/tu</a>.</p>\n</article>")])
